object Main { def main(args: Array[String]): Unit = { args.headOption match { case Some("pipeline") => AcceleratedSparkPipeline.main(args.tail) case Some("benchmark") => GPUBenchmark.main(args.tail) case Some("evaluate") => ModelEvaluator.main(args.tail) case Some("all") => println("=== Running Complete GPU-Accelerated Pipeline ===") AcceleratedSparkPipeline.main(Array()) GPUBenchmark.main(Array()) ModelEvaluator.main(Array()) println("=== All components completed successfully ===") case _ => println("Usage: sbt 'run [pipeline|benchmark|evaluate|all]'") println(" pipeline - Run the main ML pipeline") println(" benchmark - Run performance benchmarks") println(" evaluate - Evaluate trained models") println(" all - Run all components") } }
}